/**
 * @summary Get user settings
 */
export const getUserSettingsResponseBackgroundDarknessMin = 0;
export const getUserSettingsResponseBackgroundDarknessMax = 90;

export const getUserSettingsResponseTradingSessionsItemDaysItemMin = 0;
export const getUserSettingsResponseTradingSessionsItemDaysItemMax = 6;

export const getUserSettingsResponsePreMacroMinutesMin = 0;

export const GetUserSettingsResponse = zod.object({
  id: zod.number(),
  backgroundUrl: zod.string().nullish(),
  backgroundType: zod.enum(["default", "custom"]),
  fontChoice: zod.enum(["inter", "jetbrains", "roboto", "space-grotesk", "ibm-plex"]),
  backgroundDarkness: zod
    .number()
    .min(getUserSettingsResponseBackgroundDarknessMin)
    .max(getUserSettingsResponseBackgroundDarknessMax),
  language: zod.enum(["it", "en", "es", "fr", "de"]),
  tradingSessions: zod
    .array(
      zod.object({
        id: zod.string(),
        name: zod.string(),
        openUTC: zod.string().describe("Legacy field name. Stores local HH:MM time, not UTC."),
        closeUTC: zod.string().describe("Legacy field name. Stores local HH:MM time, not UTC."),
        color: zod.string(),
        kind: zod
          .enum(["trading", "market_closed"])
          .optional()
          .describe("Session kind. Missing means trading for backward compatibility."),
        days: zod
          .array(
            zod
              .number()
              .min(getUserSettingsResponseTradingSessionsItemDaysItemMin)
              .max(getUserSettingsResponseTradingSessionsItemDaysItemMax),
          )
          .optional()
          .describe(
            "Optional JavaScript weekday numbers: 0 Sunday through 6 Saturday. Missing or empty means every day.",
          ),
        enabled: zod.boolean(),
      }),
    )
    .nullish(),
  lotDivisor: zod.number().min(1),
  calendarCurrencies: zod.array(zod.string()).nullish(),
  calendarImpacts: zod.array(zod.string()).nullish(),
  dailyReminderTime: zod.string().nullish(),
  preMacroMinutes: zod.number().min(getUserSettingsResponsePreMacroMinutesMin),
  maxDailyLoss: zod.number().nullish(),
  onboardingTutorialCompletedAt: zod.date().nullish(),
  selectedPairs: zod.array(zod.string()).nullish(),
  backgroundPresets: zod
    .array(
      zod.object({
        id: zod.string(),
        name: zod.string(),
        url: zod.string(),
        isDefault: zod.boolean(),
      }),
    )
    .nullish(),
  alarmConfigs: zod.record(zod.string(), zod.unknown()).nullish(),
});

